"use client";

import { useState, useEffect } from "react";
import { toast } from "react-hot-toast";
import {
  getMenuItems,
  getCategories,
  createMenuItem,
  updateMenuItem,
  deleteMenuItem,
  createCategory,
  updateMenuItemAvailability,
  getProperties,
} from "@/lib/api";
import { useAdminStore } from "@/store/useAdminStore";

export default function MenuPage() {
  const { propertyId, user } = useAdminStore();
  const [categories, setCategories] = useState([]);
  const [items, setItems] = useState([]);
  const [properties, setProperties] = useState([]);
  const [loading, setLoading] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showItemModal, setShowItemModal] = useState(false);
  const [editingItem, setEditingItem] = useState(null);
  const [itemSaving, setItemSaving] = useState(false);
  const [imagePreview, setImagePreview] = useState("");
  const [selectedPropertyId, setSelectedPropertyId] = useState("");

  const [categoryForm, setCategoryForm] = useState({ name: "", propertyId: "" });
  const [itemForm, setItemForm] = useState({
    name: "",
    description: "",
    price: "",
    categoryId: "",
    imageUrl: "",
    propertyId: "",
  });

  useEffect(() => {
    if (propertyId || selectedPropertyId) {
      loadData();
    }
  }, [propertyId, selectedPropertyId]);

  useEffect(() => {
    if (user?.role === "super_admin") {
      fetchProperties();
    }
  }, [user]);

  const loadData = async () => {
    const effectivePropertyId = propertyId || selectedPropertyId;
    setLoading(true);
    try {
      const [categoriesRes, itemsRes] = await Promise.all([
        getCategories(effectivePropertyId),
        getMenuItems(effectivePropertyId),
      ]);
      setCategories(categoriesRes.data.data);
      setItems(itemsRes.data.data);
    } catch (err) {
      toast.error("Failed to load menu data");
    } finally {
      setLoading(false);
    }
  };

  const fetchProperties = async () => {
    try {
      const res = await getProperties();
      setProperties(res.data.data);
    } catch (err) {
      toast.error("Failed to load properties");
    }
  };

  const handleCreateCategory = async () => {
    if (!categoryForm.name.trim()) {
      toast.error("Category name is required");
      return;
    }
    if (user?.role === "super_admin" && !categoryForm.propertyId && !selectedPropertyId) {
      toast.error("Property is required");
      return;
    }
    try {
      const res = await createCategory({
        name: categoryForm.name,
        propertyId: user?.role === "super_admin" ? (categoryForm.propertyId || selectedPropertyId) : propertyId,
      });
      setCategories((prev) => [...prev, res.data.data]);
      setCategoryForm({ name: "", propertyId: "" });
      setShowCategoryModal(false);
      toast.success("Category created!");
    } catch (err) {
      console.error("Create category error:", err);
      toast.error(
        err.response?.data?.error || "Failed to create category",
      );
    }
  };

  const handleImageChange = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const base64 = event.target?.result;
      setImagePreview(base64);
      setItemForm((prev) => ({ ...prev, imageUrl: base64 }));
    };
    reader.readAsDataURL(file);
  };

  const handleCreateOrUpdateItem = async () => {
    if (!itemForm.name.trim() || !itemForm.price) {
      toast.error("Please fill in all fields");
      return;
    }
    if (user?.role === "super_admin" && !itemForm.propertyId && !selectedPropertyId) {
      toast.error("Property is required");
      return;
    }

    setItemSaving(true);
    try {
      const payload = {
        name: itemForm.name,
        description: itemForm.description,
        price: parseFloat(itemForm.price),
        categoryId: itemForm.categoryId || null,
        imageUrl: itemForm.imageUrl,
        propertyId: user?.role === "super_admin" ? (itemForm.propertyId || selectedPropertyId) : propertyId,
      };

      if (editingItem) {
        const res = await updateMenuItem(editingItem._id, payload);
        setItems((prev) =>
          prev.map((i) => (i._id === editingItem._id ? res.data.data : i)),
        );
        toast.success("Menu item updated!");
      } else {
        const res = await createMenuItem(payload);
        setItems((prev) => [...prev, res.data.data]);
        toast.success("Menu item created!");
      }

      resetForm();
      setShowItemModal(false);
    } catch (err) {
      console.error("Item operation error:", err);
      toast.error(
        err.response?.data?.error ||
          (editingItem ? "Failed to update item" : "Failed to create item"),
      );
    } finally {
      setItemSaving(false);
    }
  };

  const handleEditItem = (item) => {
    setEditingItem(item);
    setItemForm({
      name: item.name,
      description: item.description,
      price: item.price.toString(),
      categoryId: item.categoryId._id || item.categoryId,
      imageUrl: item.imageUrl || "",
      propertyId: item.propertyId || "",
    });
    setImagePreview(item.imageUrl || "");
    setShowItemModal(true);
  };

  const handleDeleteItem = async (id) => {
    if (confirm("Are you sure you want to delete this item?")) {
      try {
        await deleteMenuItem(id);
        setItems((prev) => prev.filter((i) => i._id !== id));
        toast.success("Item deleted!");
      } catch {
        toast.error("Failed to delete item");
      }
    }
  };

  const toggleAvailability = async (item) => {
    try {
      await updateMenuItemAvailability(item._id, !item.isAvailable);
      setItems((prev) =>
        prev.map((i) =>
          i._id === item._id ? { ...i, isAvailable: !i.isAvailable } : i,
        ),
      );
    } catch {
      toast.error("Failed to update availability");
    }
  };

  const getCategoryName = (categoryId) => {
    const cat = categories.find(
      (c) => c._id === (categoryId?._id || categoryId),
    );
    return cat?.name || "—";
  };

  const resetForm = () => {
    setEditingItem(null);
    setItemForm({
      name: "",
      description: "",
      price: "",
      categoryId: "",
      imageUrl: "",
      propertyId: "",
    });
    setImagePreview("");
  };

  return (
    <div className="p-8">
      <div className="mb-8">
        <h1 className="text-3xl font-bold mb-6">Menu Management</h1>

        {user?.role === "super_admin" && (
          <div className="mb-4">
            <label className="block text-sm font-medium mb-2">Select Property</label>
            <select
              value={selectedPropertyId}
              onChange={(e) => setSelectedPropertyId(e.target.value)}
              className="border border-gray-300 rounded px-3 py-2"
            >
              <option value="">Select Property</option>
              {properties.map((prop) => (
                <option key={prop._id} value={prop._id}>
                  {prop.name}
                </option>
              ))}
            </select>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4 mb-8">
          <button
            onClick={() => setShowCategoryModal(true)}
            className="bg-blue-600 text-white px-4 py-2 rounded hover:bg-blue-700"
          >
            Add Category
          </button>
          <button
            onClick={() => {
              resetForm();
              setShowItemModal(true);
            }}
            className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
          >
            Add Menu Item
          </button>
        </div>

        {loading ? (
          <p className="text-gray-500">Loading...</p>
        ) : (
          <div className="bg-white rounded-lg shadow overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-100 border-b">
                <tr>
                  <th className="px-4 py-2 text-left">Name</th>
                  <th className="px-4 py-2 text-left">Description</th>
                  <th className="px-4 py-2 text-left">Category</th>
                  <th className="px-4 py-2 text-left">Price</th>
                  <th className="px-4 py-2 text-left">Image</th>
                  <th className="px-4 py-2 text-left">Available</th>
                  <th className="px-4 py-2 text-left">Actions</th>
                </tr>
              </thead>
              <tbody>
                {items.map((item) => (
                  <tr key={item._id} className="border-b hover:bg-gray-50">
                    <td className="px-4 py-2">{item.name}</td>
                    <td className="px-4 py-2 text-sm text-gray-600">
                      {item.description}
                    </td>
                    <td className="px-4 py-2">
                      {getCategoryName(item.categoryId)}
                    </td>
                    <td className="px-4 py-2">${item.price.toFixed(2)}</td>
                    <td className="px-4 py-2">
                      {item.imageUrl ? (
                        <img
                          src={item.imageUrl}
                          alt={item.name}
                          className="w-10 h-10 rounded object-cover"
                        />
                      ) : (
                        <span className="text-gray-400 text-sm">No image</span>
                      )}
                    </td>
                    <td className="px-4 py-2">
                      <button
                        onClick={() => toggleAvailability(item)}
                        className={`px-2 py-1 rounded text-sm ${
                          item.isAvailable
                            ? "bg-green-100 text-green-700"
                            : "bg-red-100 text-red-700"
                        }`}
                      >
                        {item.isAvailable ? "Available" : "Unavailable"}
                      </button>
                    </td>
                    <td className="px-4 py-2">
                      <button
                        onClick={() => handleEditItem(item)}
                        className="text-blue-600 hover:text-blue-800 mr-3"
                      >
                        Edit
                      </button>
                      <button
                        onClick={() => handleDeleteItem(item._id)}
                        className="text-red-600 hover:text-red-800"
                      >
                        Delete
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {showCategoryModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white p-6 rounded-lg w-96">
            <h2 className="text-xl font-bold mb-4">Add Category</h2>
            <input
              type="text"
              value={categoryForm.name}
              onChange={(e) => setCategoryForm(prev => ({ ...prev, name: e.target.value }))}
              placeholder="Category name"
              className="w-full border border-gray-300 rounded px-3 py-2 mb-4"
            />
            {user?.role === "super_admin" && (
              <select
                value={categoryForm.propertyId}
                onChange={(e) => setCategoryForm(prev => ({ ...prev, propertyId: e.target.value }))}
                className="w-full border border-gray-300 rounded px-3 py-2 mb-4"
              >
                <option value="">Select Property</option>
                {properties.map((prop) => (
                  <option key={prop._id} value={prop._id}>
                    {prop.name}
                  </option>
                ))}
              </select>
            )}
            <div className="flex justify-end gap-2">
              <button
                onClick={() => setShowCategoryModal(false)}
                className="px-4 py-2 text-gray-700 border border-gray-300 rounded hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateCategory}
                className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
              >
                Create
              </button>
            </div>
          </div>
        </div>
      )}

      {showItemModal && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white p-6 rounded-lg w-96 max-h-96 overflow-y-auto">
            <h2 className="text-xl font-bold mb-4">
              {editingItem ? "Edit Menu Item" : "Add Menu Item"}
            </h2>
            <input
              type="text"
              value={itemForm.name}
              onChange={(e) =>
                setItemForm({ ...itemForm, name: e.target.value })
              }
              placeholder="Item name"
              className="w-full border border-gray-300 rounded px-3 py-2 mb-3"
            />
            <textarea
              value={itemForm.description}
              onChange={(e) =>
                setItemForm({ ...itemForm, description: e.target.value })
              }
              placeholder="Description"
              className="w-full border border-gray-300 rounded px-3 py-2 mb-3"
              rows="2"
            />
            <input
              type="number"
              value={itemForm.price}
              onChange={(e) =>
                setItemForm({ ...itemForm, price: e.target.value })
              }
              placeholder="Price"
              className="w-full border border-gray-300 rounded px-3 py-2 mb-3"
              step="0.01"
            />
            <select
              value={itemForm.categoryId}
              onChange={(e) =>
                setItemForm({ ...itemForm, categoryId: e.target.value })
              }
              className="w-full border border-gray-300 rounded px-3 py-2 mb-3"
            >
              <option value="">Select Category</option>
              {categories.map((cat) => (
                <option key={cat._id} value={cat._id}>
                  {cat.name}
                </option>
              ))}
            </select>
            {user?.role === "super_admin" && (
              <select
                value={itemForm.propertyId}
                onChange={(e) =>
                  setItemForm({ ...itemForm, propertyId: e.target.value })
                }
                className="w-full border border-gray-300 rounded px-3 py-2 mb-3"
              >
                <option value="">Select Property</option>
                {properties.map((prop) => (
                  <option key={prop._id} value={prop._id}>
                    {prop.name}
                  </option>
                ))}
              </select>
            )}
            <div className="mb-3">
              <label className="block text-sm font-medium mb-2">Image</label>
              <input
                type="file"
                accept="image/*"
                onChange={handleImageChange}
                className="w-full"
              />
              {imagePreview && (
                <img
                  src={imagePreview}
                  alt="Preview"
                  className="w-32 h-32 rounded mt-2 object-cover"
                />
              )}
            </div>
            <div className="flex justify-end gap-2">
              <button
                onClick={() => {
                  setShowItemModal(false);
                  resetForm();
                }}
                className="px-4 py-2 text-gray-700 border border-gray-300 rounded hover:bg-gray-50"
              >
                Cancel
              </button>
              <button
                onClick={handleCreateOrUpdateItem}
                disabled={itemSaving}
                className="px-4 py-2 bg-green-600 text-white rounded hover:bg-green-700 disabled:opacity-50"
              >
                {itemSaving ? "Saving..." : editingItem ? "Update" : "Create"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
